INSERT INTO public.trivia_questions (question_text, option_a, option_b, option_c, option_d, correct_answer, difficulty, category, explanation, var_reviewed, is_auto_generated)
VALUES
('¿Qué país ganó la primera Copa Mundial de la FIFA en 1930?', 'Argentina', 'Italia', 'Uruguay', 'Brasil', 'c', 1, 'Campeones', 'Como país anfitrión del torneo inaugural, Uruguay se coronó primer campeón del mundo tras vencer a Argentina 4-2 en la gran final disputada en el histórico Estadio Centenario de Montevideo.', true, false),
('¿Cuántos títulos mundiales tiene Brasil?', '5', '3', '6', '4', 'a', 1, 'Campeones', 'Brasil es la selección más laureada en la historia de los mundiales con cinco coronas conseguidas en Suecia 1958, Chile 1962, México 1970, Estados Unidos 1994 y Corea-Japón 2002.', true, false),
('¿En qué país se jugó el Mundial 2018?', 'Catar', 'Rusia', 'Sudáfrica', 'Brasil', 'b', 1, 'Sedes', 'La XXI edición de la Copa Mundial se disputó en Rusia, siendo la primera vez que un país de Europa Oriental albergaba este certamen deportivo, con partidos jugados en 11 ciudades diferentes.', true, false),
('¿Quién es el máximo goleador histórico de los Mundiales?', 'Ronaldo', 'Gerd Müller', 'Just Fontaine', 'Miroslav Klose', 'd', 1, 'Goleadores', 'El delantero alemán Miroslav Klose ostenta el récord histórico con 16 goles anotados en 24 partidos jugados a lo largo de cuatro ediciones consecutivas (2002, 2006, 2010 y 2014).', true, false),
('¿Qué selección ganó el Mundial de 2022?', 'Francia', 'Argentina', 'Brasil', 'Alemania', 'b', 1, 'Campeones', 'Liderada por Lionel Messi, la Albiceleste bordó su tercera estrella mundial en el pecho tras imponerse a Francia en una de las finales más dramáticas de la historia, decidida en la tanda de penaltis.', true, false),
('¿Quién marcó el gol de “La Mano de Dios”?', 'Pelé', 'Lionel Messi', 'Diego Maradona', 'Zinedine Zidane', 'c', 1, 'Momentos Históricos', 'Diego Armando Maradona convirtió este mítico gol con el puño en los cuartos de final de México 1986 contra Inglaterra, apenas unos minutos antes de firmar el antológico ''Gol del Siglo''.', true, false),
('¿Qué país organizó el Mundial 2014?', 'Alemania', 'Brasil', 'Argentina', 'Sudáfrica', 'b', 1, 'Sedes', 'Brasil acogió el torneo de 2014, regresando como anfitrión por segunda vez en su historia (después de 1950), en una edición recordada por el asombroso 7-1 encajado ante Alemania.', true, false),
('¿Cuál es la mascota del Mundial de México 1986?', 'Naranjito', 'Ciao', 'Footix', 'Pique', 'd', 1, 'Curiosidades', 'Pique era un chile jalapeño gigante con sombrero de mariachi y un gran bigote, lo que representaba el picante y el folclor tradicional de la cultura mexicana.', true, false),
('¿Qué país es conocido como “La Canarinha”?', 'Brasil', 'Argentina', 'Uruguay', 'Portugal', 'a', 1, 'Selecciones', 'La selección brasileña recibe el apodo de ''La Canarinha'' (Pequeño Canario) debido al brillante uniforme amarillo y verde que adoptaron tras la dura derrota del Maracanazo en 1950.', true, false),
('¿Quién ganó el Balón de Oro del Mundial 2014?', 'Thomas Müller', 'Arjen Robben', 'Lionel Messi', 'James Rodríguez', 'c', 1, 'Jugadores', 'Lionel Messi fue distinguido con el Balón de Oro al mejor futbolista de la Copa Mundial de Brasil 2014 tras liderar a la selección argentina hasta el partido de la gran final.', true, false),
('¿Qué selección tiene más subcampeonatos mundiales?', 'Argentina', 'Alemania', 'Países Bajos', 'Checoslovaquia', 'b', 1, 'Finales', 'Alemania ostenta el récord de haber perdido más finales mundiales con 4 derrotas en total (ocurridas en las ediciones de 1966, 1982, 1986 y 2002).', true, false),
('¿En qué año se introdujo la tarjeta amarilla y roja en los Mundiales?', '1966', '1974', '1970', '1978', 'c', 1, 'Historia', 'Las tarjetas de amonestación y expulsión fueron introducidas en México 1970 para superar las barreras idiomáticas entre árbitros y jugadores, aunque la primera tarjeta roja directa se mostró recién en 1974.', true, false),
('¿Quién anotó el gol del título en la final de 2010?', 'Xavi Hernández', 'Andrés Iniesta', 'David Villa', 'Fernando Torres', 'b', 1, 'Finales', 'Andrés Iniesta grabó su nombre en la inmortalidad del fútbol español al marcar un agónico derechazo en el minuto 116 de la prórroga ante los Países Bajos, dando a España su único Mundial.', true, false),
('¿Qué futbolista apodado “O Rei” ganó tres Copas del Mundo?', 'Zico', 'Romário', 'Pelé', 'Ronaldo', 'c', 1, 'Jugadores', 'Edson Arantes do Nascimento, Pelé, es el único jugador en la historia del fútbol que ha ganado tres Mundiales como futbolista activo (Suecia 1958, Chile 1962 y México 1970).', true, false),
('¿Cuál fue el país anfitrión del Mundial 2006?', 'Francia', 'Italia', 'Alemania', 'Inglaterra', 'c', 1, 'Sedes', 'Alemania fue el escenario del Mundial 2006, un evento sumamente aclamado por su organización, infraestructura de vanguardia y el excelente clima festivo en las calles.', true, false),
('¿Qué país es el único que ha participado en todas las ediciones de la Copa del Mundo?', 'Alemania', 'Argentina', 'Brasil', 'Italia', 'c', 1, 'Selecciones', 'La pentacampeona Brasil ostenta la perfecta marca de haber clasificado y jugado en las 22 fases finales de la Copa Mundial de la FIFA disputadas desde 1930 hasta 2022.', true, false),
('¿En qué estadio se jugó la final del Mundial 2022?', 'Maracaná', 'Lusail', 'Wembley', 'Estadio Azteca', 'b', 1, 'Sedes', 'El majestuoso Estadio Icónico de Lusail, con capacidad para más de 88.000 espectadores, fue el recinto donde Argentina derrotó a Francia en los penaltis para consagrarse campeona.', true, false),
('¿Quién era el entrenador de España campeón en 2010?', 'Vicente del Bosque', 'Luis Aragonés', 'Julen Lopetegui', 'Luis Enrique', 'a', 1, 'Historia', 'Vicente del Bosque heredó el excelente plantel campeón de la Eurocopa 2008 y lo guio con calma y sabiduría táctica hasta la conquista de la Copa del Mundo en Sudáfrica 2010.', true, false),
('¿Qué selección ganó su primer Mundial en 2010?', 'Países Bajos', 'Portugal', 'España', 'Inglaterra', 'c', 1, 'Campeones', 'Tras un largo historial de frustraciones mundialistas, la generación dorada de la ''Roja'' conquistó su primer y único título en la Copa del Mundo disputada en tierras sudafricanas.', true, false),
('¿Quién anotó el gol más rápido en un Mundial (11 segundos)?', 'Hakan Şükür', 'Clint Dempsey', 'Bryan Robson', 'Robert Lewandowski', 'a', 1, 'Récords', 'El artillero turco Hakan Şükür batió el récord de velocidad al marcarle a Corea del Sur en el partido por el tercer puesto del Mundial 2002 con apenas 11 segundos de juego.', true, false),
('¿Qué jugador ha sido campeón del mundo como futbolista y como entrenador?', 'Mario Zagallo', 'Franz Beckenbauer', 'Didier Deschamps', 'Todos los anteriores', 'd', 2, 'Historia', 'Esta exclusiva hazaña solo pertenece a tres leyendas: Zagallo (campeón 1958/1962 y 1970), Beckenbauer (1974 y 1990) y Deschamps (1998 y 2018).', true, false),
('¿Quién ganó el Mundial de 1966?', 'Alemania Federal', 'Inglaterra', 'Portugal', 'Unión Soviética', 'b', 2, 'Campeones', 'La selección inglesa aprovechó su condición de anfitriona para alzarse con su primer y único Mundial de la historia, derrotando a Alemania Federal en una recordada y polémica prórroga por 4-2.', true, false),
('¿En qué Mundial se implementó por primera vez la tecnología de línea de gol?', '2010', '2018', '2014', '2006', 'c', 2, 'Historia', 'La FIFA aprobó el uso del sistema tecnológico de cámaras ''GoalControl'' para el Mundial de Brasil 2014, evitando así goles fantasmas polémicos como los ocurridos en ediciones anteriores.', true, false),
('¿Qué jugador anotó en cinco Mundiales consecutivos?', 'Pelé', 'Cristiano Ronaldo', 'Uwe Seeler', 'Miroslav Klose', 'b', 2, 'Goleadores', 'El astro portugués Cristiano Ronaldo hizo historia en Qatar 2022 al convertirse en el primer futbolista de todos los tiempos en meter al menos un gol en cinco mundiales seguidos (2006, 2010, 2014, 2018 y 2022).', true, false),
('¿Quién fue el máximo goleador de Francia 1998?', 'Ronaldo', 'Gabriel Batistuta', 'Davor Šuker', 'Christian Vieri', 'c', 2, 'Goleadores', 'El delantero croata Davor Šuker guio a su selección a un histórico tercer puesto en el Mundial 1998 anotando 6 goles, lo que le valió ganar la codiciada Bota de Oro.', true, false),
('¿Qué selección africana llegó por primera vez a cuartos de final?', 'Senegal', 'Camerún', 'Ghana', 'Nigeria', 'b', 2, 'Selecciones', 'Conducida por el carismático veterano Roger Milla, la selección de Camerún sorprendió al mundo en Italia 1990 al convertirse en el primer equipo africano en avanzar hasta los cuartos de final.', true, false),
('¿Cuál fue la mascota de España 1982?', 'Naranjito', 'Pique', 'Ciao', 'Footix', 'a', 2, 'Curiosidades', 'Naranjito, una simpática naranja vestida con el uniforme de la selección española, rompió con las tradicionales mascotas de animales o niños personificados de épocas pasadas.', true, false),
('¿Quién falló el penal definitivo en la final de 1994?', 'Franco Baresi', 'Daniele Massaro', 'Roberto Baggio', 'Demetrio Albertini', 'c', 2, 'Finales', 'A pesar de haber hecho un torneo espectacular que metió a Italia en la final, la estrella Roberto Baggio mandó el balón por encima del travesaño, sellando el cuarto título mundial de Brasil.', true, false),
('¿En qué país se celebró el Mundial 2002?', 'Corea del Sur y Japón', 'Corea del Sur', 'Japón', 'China', 'a', 2, 'Sedes', 'El Mundial de 2002 fue un certamen histórico al convertirse en el primero en ser organizado de manera conjunta por dos países, así como el primero en jugarse en suelo asiático.', true, false),
('¿Quién fue el portero titular de Italia en el Mundial 2006?', 'Francesco Toldo', 'Gianluigi Buffon', 'Fabio Cannavaro', 'Dino Zoff', 'b', 2, 'Jugadores', 'Un imbatible Gianluigi Buffon defendió el arco de la Azzurra en Alemania 2006, recibiendo apenas 2 goles en los 7 partidos del torneo (un autogol de Zaccardo y un penalti de Zidane).', true, false),
('¿Cuántos goles anotó Just Fontaine en Suecia 1958?', '10', '11', '13', '15', 'c', 2, 'Goleadores', 'El delantero francés Just Fontaine mantiene un asombroso récord inalcanzable al anotar la friolera de 13 goles en un solo campeonato del mundo (Suecia 1958).', true, false),
('¿Qué selección ganó el Mundial de 1978?', 'Países Bajos', 'Argentina', 'Brasil', 'Italia', 'b', 2, 'Campeones', 'Organizando el campeonato, Argentina se consagró por primera vez en su historia al vencer 3-1 a los Países Bajos tras disputarse una emocionante prórroga en el Estadio Monumental.', true, false),
('¿Quién fue el capitán de Argentina campeón en 1986?', 'Diego Maradona', 'Daniel Passarella', 'Oscar Ruggeri', 'Jorge Valdano', 'a', 2, 'Jugadores', 'Diego Armando Maradona portó el brazalete de capitán liderando con jerarquía absoluta y maestría futbolística el camino de la Albiceleste hacia su segunda Copa del Mundo.', true, false),
('¿En qué Mundial se introdujo el gol de oro?', '1994', '1998', '2002', '1990', 'b', 2, 'Historia', 'La regla de muerte súbita debutó en Francia 1998; el primer jugador en anotar un gol de oro mundialista fue el defensor francés Laurent Blanc en octavos de final contra Paraguay.', true, false),
('¿Qué país organizó el Mundial 1994?', 'México', 'Estados Unidos', 'Canadá', 'Brasil', 'b', 2, 'Sedes', 'A pesar de la incredulidad inicial de los fanáticos del fútbol tradicional, Estados Unidos 1994 se convirtió en el Mundial con la mayor asistencia promedio de la historia (casi 69.000 espectadores por partido).', true, false),
('¿Quién es el futbolista con más partidos disputados en Mundiales?', 'Lothar Matthäus', 'Lionel Messi', 'Paolo Maldini', 'Miroslav Klose', 'b', 2, 'Récords', 'Lionel Messi superó a Lothar Matthäus al disputar la final de Qatar 2022, sumando un total de 26 partidos jugados en Copas del Mundo a lo largo de cinco ediciones.', true, false),
('¿Qué selección fue campeona en 1954 en el “Milagro de Berna”?', 'Alemania Federal', 'Hungría', 'Austria', 'Uruguay', 'a', 2, 'Campeones', 'Se llamó el ''Milagro de Berna'' porque la humilde selección de Alemania Federal remontó un 2-0 inicial para derrotar 3-2 a los poderosos ''Magiares Mágicos'' de Hungría, que llevaban un invicto de 4 años.', true, false),
('¿En qué sede se jugó la primera final decidida por penales?', '1990', '1994', '1998', '1978', 'b', 2, 'Finales', 'El Rose Bowl de Pasadena, California, albergó la final de EE. UU. 1994, donde Brasil y Italia empataron a cero goles en los 120 minutos, coronando a los sudamericanos desde el punto penal.', true, false),
('¿Quién ganó la Bota de Oro del Mundial 2010?', 'Thomas Müller', 'David Villa', 'Wesley Sneijder', 'Diego Forlán', 'a', 2, 'Goleadores', 'A pesar de quedar empatado a 5 goles con Villa, Sneijder y Forlán, el jovencísimo Thomas Müller ganó el premio de goleador oficial gracias a sus tres asistencias dadas en el torneo.', true, false),
('¿Quién anotó el primer gol de la Copa del Mundo 2022?', 'Enner Valencia', 'Lionel Messi', 'Kylian Mbappé', 'Bukayo Saka', 'a', 2, 'Curiosidades', 'El delantero ecuatoriano Enner Valencia anotó el primer gol oficial de Qatar 2022 mediante un lanzamiento penal en el partido inaugural frente a la selección anfitriona de Catar.', true, false),
('¿Quién es el único jugador que ha marcado en todas las rondas de un mismo Mundial (grupos, octavos, cuartos, semifinal y final)?', 'Pelé', 'Gerd Müller', 'Jairzinho', 'Paolo Rossi', 'c', 3, 'Récords', 'El implacable extremo brasileño Jairzinho anotó goles en los seis partidos consecutivos que disputó Brasil en México 1970 (fase de grupos, cuartos, semis y final), una gesta perfecta y nunca repetida.', true, false),
('¿Qué selección ha perdido más finales de la Copa del Mundo?', 'Argentina', 'Países Bajos', 'Alemania', 'Checoslovaquia', 'c', 3, 'Campeones', 'Aunque cuenta con cuatro Copas mundiales, la Mannschaft también ha sido la selección que más veces ha quedado en el segundo puesto, cayendo en las finales de 1966, 1982, 1986 y 2002.', true, false),
('¿Cuál fue el primer país en organizar dos Mundiales?', 'Italia', 'México', 'Francia', 'Brasil', 'b', 3, 'Sedes', 'México recibió la sede por segunda vez en 1986 tras la renuncia forzada de Colombia debido a dificultades financieras, convirtiéndose en el primer bicampeón organizador de la historia.', true, false),
('¿Qué jugador anotó dos goles en la final de 1998?', 'Zinedine Zidane', 'Thierry Henry', 'Emmanuel Petit', 'David Trezeguet', 'a', 3, 'Finales', 'Zinedine Zidane se convirtió en héroe nacional en Francia 1998 al batir por duplicado con sendos testazos la portería brasileña en el Stade de France.', true, false),
('¿Qué guardameta ganó el Balón de Oro en el Mundial 2002?', 'Iker Casillas', 'Gianluigi Buffon', 'Manuel Neuer', 'Oliver Kahn', 'd', 3, 'Jugadores', 'A pesar de cometer un doloroso fallo en la final, Oliver Kahn cuajó una actuación tan soberbia y determinante con Alemania que fue galardonado con el trofeo al Mejor Jugador del certamen.', true, false),
('¿En qué partido se marcaron 12 goles, récord en la historia de los Mundiales?', 'Austria 7-5 Suiza (1954)', 'Brasil 6-5 Polonia (1938)', 'Hungría 10-1 El Salvador (1982)', 'Alemania 8-0 Arabia Saudita (2002)', 'a', 3, 'Récords', 'En los cuartos de final de Suiza 1954, bajo un calor sofocante, Austria y Suiza protagonizaron la llamada ''Batalla del calor de Lausana'' que terminó en un increíble marcador de 7-5.', true, false),
('¿Quién es el único futbolista en marcar un gol olímpico (directo de saque de esquina) en la Copa del Mundo?', 'Marcos Coll', 'Diego Maradona', 'Roberto Carlos', 'David Beckham', 'a', 3, 'Curiosidades', 'El colombiano Marcos Coll asombró al mundo en Chile 1962 al marcar un gol olímpico al legendario arquero soviético Lev Yashin, apodado la ''Araña Negra''.', true, false),
('¿En qué edición se disputó la primera tanda de penales?', '1978', '1986', '1982', '1974', 'c', 3, 'Historia', 'Ocurrió en la mítica semifinal de España 1982 entre Alemania Federal y Francia. Tras empatar 3-3, los germanos prevalecieron 5-4 en la primera definición desde los once metros.', true, false),
('¿Quién es el jugador más joven en marcar en una final de la Copa del Mundo?', 'Kylian Mbappé', 'Pelé', 'Lionel Messi', 'Michael Owen', 'b', 3, 'Récords', 'Con apenas 17 años y 249 days de edad, ''O Rei'' Pelé anotó un doblete de antología contra Suecia en la final del torneo de 1958.', true, false),
('¿Qué selección ganó el Mundial sin recibir goles en las eliminatorias (octavos, cuartos, semifinal y final)?', 'Italia 2006', 'España 2010', 'Francia 1998', 'Brasil 2002', 'b', 3, 'Récords', 'La imponente zaga de España 2010 encadenó cuatro porterías a cero consecutivas en las rondas KO, derrotando 1-0 de manera sucesiva a Portugal, Paraguay, Alemania y Países Bajos.', true, false),
('¿Qué jugador tiene el récord de asistencias en Copas del Mundo?', 'Diego Maradona', 'Lionel Messi', 'Pelé', 'Bastian Schweinsteiger', 'c', 3, 'Goleadores', 'Pelé ostenta el récord histórico de asistencias en los Mundiales con un total de 10 pases de gol, incluyendo un récord de seis asistencias logradas solo en el torneo de México 1970.', true, false),
('¿Cuál es el marcador más abultado en un partido mundialista (diferencia de 9 goles)?', 'Hungría 9-0 Corea del Sur (1954)', 'Yugoslavia 9-0 Zaire (1974)', 'Hungría 10-1 El Salvador (1982)', 'Todos los anteriores', 'd', 3, 'Récords', 'Los tres partidos acabaron con una colosal diferencia de nueve tantos, siendo el Hungría 10-1 El Salvador de España 1982 el único encuentro mundialista donde una selección alcanzó los diez goles.', true, false),
('¿En qué edición se anotaron más goles en la historia de los Mundiales?', '1998', '2014', '2018', '2022', 'd', 3, 'Récords', 'El emocionante Mundial de Qatar 2022 registró el récord total con 172 anotaciones superando las marcas previas de Francia 1998 y Brasil 2014, que tenían 171.', true, false),
('¿Quién ha conseguido un hat-trick en una final de la Copa del Mundo?', 'Geoff Hurst', 'Geoff Hurst y Kylian Mbappé', 'Kylian Mbappé', 'Lionel Messi', 'b', 3, 'Finales', 'El inglés Geoff Hurst fue el primero en 1966 y el astro francés Kylian Mbappé igualó la mítica gesta en la emocionante final de Qatar 2022 ante Argentina.', true, false),
('¿Qué selección de remontó un 0-3 en contra para ganar 5-3 en cuartos de final de 1966?', 'Alemania Federal', 'Portugal', 'Italia', 'Inglaterra', 'b', 3, 'Historia', 'Corea del Norte ganaba de forma sorpresiva 3-0 en el primer tiempo, pero la genialidad y potencia de la ''Pantera Negra'' Eusébio, anotando 4 goles, lideró una remontada épica para los lusos.', true, false),
('¿Cuál fue el primer Mundial con 32 selecciones?', '1982', '1994', '1998', '2002', 'c', 3, 'Historia', 'La FIFA decidió ampliar el cupo de participantes de 24 a 32 selecciones en Francia 1998, permitiendo así mayor representatividad de federaciones africanas, asiáticas y americanas.', true, false),
('¿Qué portero levantó el trofeo como capitán de su selección en un Mundial?', 'Dino Zoff (1982)', 'Ambos', 'Iker Casillas (2010)', 'Ninguno', 'b', 3, 'Jugadores', 'Los arqueros Dino Zoff (capitán de Italia a los 40 años en España 1982) e Iker Casillas (capitán y salvador de España en Sudáfrica 2010) tuvieron el honor de alzar la Copa.', true, false),
('¿Quién marcó el gol número 1000 en la historia de la Copa del Mundo?', 'Rob Rensenbrink', 'Johan Cruyff', 'Gerd Müller', 'Pelé', 'a', 3, 'Récords', 'El neerlandés Rob Rensenbrink anotó el gol número 1000 en la historia de los Mundiales al convertir un penal en el partido entre Países Bajos y Escocia en Argentina 1978.', true, false),
('¿Qué selecciones han ganado la Copa del Mundo en dos siglos distintos (XX y XXI)?', 'Brasil', 'Argentina', 'Ambas', 'Ninguna', 'c', 3, 'Campeones', 'Ambas selecciones alcanzaron la gloria máxima en el siglo pasado, y en el presente siglo Brasil conquistó la edición de 2002 mientras que Argentina hizo lo propio en 2022.', true, false),
('¿Qué footballer ha participado en la Copa del Mundo con tres selecciones diferentes?', 'Dejan Stanković', 'Alfredo Di Stéfano', 'Robert Prosinečki', 'Luka Modrić', 'a', 4, 'Curiosidades', 'Dejan Stanković jugó para Yugoslavia en 1998, luego capitaneó a Serbia y Montenegro en 2006, y finalmente defendió el escudo de Serbia en el Mundial de Sudáfrica 2010.', true, false),
('¿En qué Mundial se usó por primera vez el balón con diseño de pentágonos negros (Telstar)?', '1966', '1970', '1974', '1962', 'b', 4, 'Historia', 'Adidas presentó el icónico modelo ''Telstar'' en México 1970, diseñado con pentágonos negros y hexágonos blancos para facilitar la visibilidad en las pantallas de televisión en blanco y negro de la época.', true, false),
('¿Quién es el máximo goleador de una sola edición de la Copa del Mundo?', 'Just Fontaine', 'Gerd Müller', 'Sándor Kocsis', 'Ronaldo', 'a', 4, 'Goleadores', 'Just Fontaine ostenta este gran hito al marcar 13 goles con la selección francesa en la Copa Mundial de Suecia 1958, una hazaña irrepetible para el fútbol moderno.', true, false),
('¿Qué partido ostenta el récord de más tarjetas amarillas (16) en un mismo encuentro?', 'Portugal vs Países Bajos 2006', 'Argentina vs Alemania 2006', 'Italia vs España 1994', 'Brasil vs Colombia 2014', 'a', 4, 'Récords', 'Conocido como la ''Batalla de Núremberg'', el árbitro Valentin Ivanov mostró 16 tarjetas amarillas y un récord de 4 tarjetas rojas por doble amonestación en un partido sumamente de tensión.', true, false),
('¿Quién fue el primer jugador en marcar un gol en propia puerta en una final de la Copa del Mundo?', 'Mario Mandžukić', 'Roberto Ayala', 'Igor Belanov', 'Andreas Brehme', 'a', 4, 'Finales', 'El croata Mario Mandžukić desvió involuntariamente el balón de cabeza tras un tiro libre en la final de Rusia 2018, abriendo el marcador para Francia a los 18 minutos.', true, false),
('¿Qué selección tiene el récord de partidos consecutivos ganados en Mundiales?', 'Brasil', 'Italia', 'Alemania', 'Argentina', 'a', 4, 'Récords', 'La Canarinha acumuló 11 victorias consecutivas en Mundiales: ganó todos sus encuentros de la edición 2002 (7 partidos) y venció en los 4 primeros compromisos de Alemania 2006.', true, false),
('¿Cuál fue el primer Mundial que se transmitió por televisión en directo?', '1950', '1954', '1958', '1962', 'b', 4, 'Historia', 'El Mundial de Suiza 1954 marcó un antes y un después en las transmisiones televisivas globales al retransmitirse por primera vez encuentros en directo gracias a la recién fundada red Eurovisión.', true, false),
('¿Quién fue el primer ganador del Guante de Oro al mejor portero de la Copa del Mundo?', 'Michel Preud''homme', 'Oliver Kahn', 'Gianluigi Buffon', 'Iker Casillas', 'a', 4, 'Jugadores', 'El belga Michel Preud''homme fue galardonado con el trofeo Lev Yashin (precursor del actual Guante de Oro) en EE. UU. 1994 gracias a sus impresionantes atajadas bajo los tres palos.', true, false),
('¿Quién marcó el gol número 2000 en la historia de la Copa del Mundo?', 'Marcus Allbäck', 'Miroslav Klose', 'Ronaldo', 'Andriy Shevchenko', 'a', 4, 'Récords', 'El delantero sueco Marcus Allbäck firmó este gol hito con un cabezazo histórico durante un disputado empate 2-2 contra Inglaterra en la fase de grupos del Mundial de Alemania 2006.', true, false),
('¿Quién fue el primer futbolista en ser expulsado en dos ediciones distintas de la Copa del Mundo?', 'Rigobert Song', 'Zinedine Zidane', 'David Beckham', 'Claudio Gentile', 'a', 4, 'Jugadores', 'El recio defensor camerunés Rigobert Song vio la cartulina roja contra Brasil en EE. UU. 1994 a los 17 años de edad, y posteriormente volvió a ser expulsado ante Chile en Francia 1998.', true, false),
('--Qué selección fue subcampeona en 1974 siendo conocida como la “Naranja Mecánica”?', 'Países Bajos', 'Alemania Federal', 'Brasil', 'Argentina', 'a', 4, 'Finales', 'Comandada por Johan Cruyff en el campo y Rinus Michels en el banco, la selección de los Países Bajos deslumbró al mundo con su revolucionario ''Fútbol Total'', aunque cayó 2-1 ante el anfitrión en la final.', true, false),
('¿Quién fue el autor del primer gol en la historia de los Mundiales?', 'Lucien Laurent', 'Guillermo Stábile', 'Pedro Cea', 'Bert Patenaude', 'a', 4, 'Historia', 'El francés Lucien Laurent pasó a la eternidad del fútbol el 13 de julio de 1930 al marcar una hermosa volea en el minuto 19 del encuentro inaugural donde Francia goleó 4-1 a México.', true, false),
('¿En qué Mundial se otorgó por primera vez el trofeo de la Copa del Mundo actual (Trofeo de la FIFA)?', '1970', '1974', '1978', '1930', 'b', 4, 'Historia', 'Tras adjudicarse Brasil el trofeo Jules Rimet a perpetuidad en 1970, la FIFA introdujo la actual escultura de oro diseñada por Silvio Gazzaniga para el Mundial de Alemania Occidental 1974.', true, false),
('¿Quién es el único jugador en marcar 5 goles en un mismo partido mundialista?', 'Oleg Salenko', 'Gerd Müller', 'Just Fontaine', 'Sándor Kocsis', 'a', 4, 'Goleadores', 'El atacante ruso Oleg Salenko destrozó las redes de Camerún anotando cinco tantos en la fase de grupos de EE. UU. 1994, estableciendo una plusmarca que aún sigue intacta.', true, false),
('¿Cuál fue el primer Mundial con transmisión en color?', '1966', '1970', '1974', '1978', 'b', 4, 'Historia', 'México 1970 representó una enorme revolución para la industria mediática al transmitirse en color y en directo a millones de hogares de todo el mundo mediante telecomunicación satelital.', true, false),
('¿Qué selección ha disputado más Copas del Mundo sin haber sido campeona?', 'México', 'Países Bajos', 'Suecia', 'Croacia', 'a', 4, 'Selecciones', 'La selección de México es la que cuenta con mayor cantidad de participaciones mundialistas (17 ediciones) sin haber levantado jamás el ansiado título máximo del fútbol.', true, false),
('¿Quién ejecutó y marcó el primer penalti de una tanda en la historia de los Mundiales?', 'Alain Giresse', 'Paul Breitner', 'Uli Stielike', 'Maxime Bossis', 'a', 4, 'Historia', 'El centrocampista francés Alain Giresse abrió con maestría la tanda en la dramática e histórica semifinal de España 1982 disputada entre Francia y Alemania Federal.', true, false),
('¿En qué edición se utilizó por primera vez el VAR?', '2014', '2018', '2022', '2010', 'b', 4, 'Historia', 'La tecnología de videoarbitraje (VAR) hizo su debut absoluto en el Mundial de Rusia 2018, lo que disparó de inmediato el número total de penaltis de juego concedidos en el certamen.', true, false),
('¿Quién posee el récord de más penaltis marcados en la historia de la Copa del Mundo (sin tandas)?', 'Eusébio', 'Gabriel Batistuta', 'Harry Kane', 'Todos comparten el récord', 'd', 4, 'Goleadores', 'Eusébio (en 1966), Rob Rensenbrink (en 1978), Gabriel Batistuta (en 1994 y 1998), Lionel Messi (en 2018 y 2022) y Harry Kane (en 2018 y 2022) comparten el récord absoluto con 4 penaltis convertidos.', true, false),
('¿Cuál es la única selección que ha terminado un Mundial sin recibir goles?', 'Suiza 2006', 'Italia 1990', 'Brasil 1994', 'Alemania 2014', 'a', 4, 'Récords', 'Suiza completó el torneo de Alemania 2006 sin recibir un solo gol en sus cuatro duelos reglamentarios, cayendo eliminada por la vía de los penaltis en los octavos de final ante Ucrania.', true, false),
('¿Quién posee el récord del gol más rápido anotado por un suplente en la Copa del Mundo?', 'Ebbe Sand', 'Richard Morales', 'Lasse Vibe', 'Denílson', 'a', 5, 'Curiosidades', 'El danés Ebbe Sand ingresó de cambio en el duelo frente a Nigeria en Francia 1998 y batió la red rival tras apenas transcurrir 16 segundos de haber ingresado en el césped.', true, false),
('¿Cuál es el récord de goles recibidos por una selección en un mismo Mundial?', '16', '14', '15', '17', 'a', 5, 'Récords', 'La desafortunada marca recae sobre el guardameta Luis Guevara Mora de El Salvador en España 1982, encajando un total de 16 goles, incluyendo el doloroso 10-1 frente a Hungría.', true, false),
('¿Qué guardameta ha marcado un gol en la historia de los Mundiales?', 'José Luis Chilavert', 'Rogério Ceni', 'René Higuita', 'Ninguno', 'd', 5, 'Curiosidades', 'Pese a los audaces intentos de porteros de gran golpeo de balón como el paraguayo José Luis Chilavert, ningún guardameta de la historia ha logrado mandar el esférico a la red en una fase final del torneo.', true, false),
('¿Quién anotó el primer autogol en la historia de la Copa del Mundo?', 'Ernst Lörtscher', 'Manuel Rosas', 'José Nasazzi', 'Severino Minelli', 'a', 5, 'Historia', 'El defensa suizo Ernst Lörtscher registró el primer autogol verificado de la historia mundialista al desviar el balón contra su portería ante Alemania en el Mundial de Francia 1938.', true, false),
('¿Quién registró más asistencias en una misma edición de la Copa del Mundo?', 'Pelé', 'Diego Maradona', 'Lionel Messi', 'Thomas Müller', 'a', 5, 'Goleadores', 'El rey Pelé conserva este hito al firmar 6 majestuosas asistencias de gol para que Brasil aplastara y maravillara a los rivales durante la edición de México 1970.', true, false),
('¿Quién fue el primer jugador en ser expulsado en una final de la Copa del Mundo?', 'Pedro Monzón', 'Zinedine Zidane', 'Marcel Desailly', 'Claudio Gentile', 'a', 5, 'Finales', 'El defensa argentino Pedro Monzón pasó a los libros de historia al recibir una tarjeta roja directa a los 65 minutos de la áspera final del Mundial de Italia 1990 frente a Alemania.', true, false),
('¿Cuál es el récord de goles anotados por una selección en un mismo torneo?', '27', '25', '23', '29', 'a', 5, 'Récords', 'La mítica selección de Hungría, liderada por Ferenc Puskás, anotó un récord absoluto de 27 goles en los 5 partidos jugados de la Copa del Mundo de Suiza 1954 (un promedio de 5,4 goles por partido).', true, false),
('¿Quién es el futbolista de mayor edad en jugar un Mundial?', 'Essam El-Hadary', 'Faryd Mondragón', 'Roger Milla', 'Dino Zoff', 'a', 5, 'Récords', 'A los 45 años y 161 días de edad, el guardameta egipcio Essam El-Hadary estableció la marca de longevidad al atajar como titular en el encuentro de Rusia 2018 frente a Arabia Saudí.', true, false),
('¿Quién anotó el gol más tardío en tiempo extra de un partido mundialista?', 'Abdelmoumene Djabou', 'John Aloisi', 'Michael Owen', 'Rudi Völler', 'a', 5, 'Récords', 'El argelino Abdelmoumene Djabou batió el arco de Alemania en el minuto 120 y 58 segundos de la prórroga durante los octavos de final disputados en Brasil 2014.', true, false),
('¿Quién fue el primer jugador en fallar un penal durante el tiempo reglamentario de una final de la Copa del Mundo?', 'Antonio Cabrini', 'Roberto Baggio', 'Johan Neeskens', 'David Trezeguet', 'a', 5, 'Finales', 'En España 1982, el italiano Antonio Cabrini remató desviado su tiro libre desde los once metros en el primer tiempo de la final contra Alemania, aunque la Azzurra terminó ganando 3-1.', true, false),
('¿Quién tiene el récord de más penaltis atajados en tandas mundialistas?', 'Harald Schumacher', 'Sergio Goycochea', 'Danijel Subašić', 'Todos ellos (4)', 'd', 5, 'Curiosidades', 'Schumacher, Goycochea, Subašić y Dominik Livaković (Qatar 2022) comparten el récord histórico con un total de 4 penaltis atajados en tandas de desempate.', true, false),
('¿Qué selección ganó el primer Premio al Juego Limpio de la FIFA?', 'Perú', 'Inglaterra', 'Brasil', 'Alemania Federal', 'a', 5, 'Historia', 'La elegante selección peruana de México 1970, liderada por Teófilo Cubillas, se llevó este honor inaugural al no recibir una sola amonestación o expulsión en todo el torneo.', true, false),
('¿Algún jugador ha marcado en tres finales de la Copa del Mundo?', 'Pelé', 'Vavá', 'Paul Breitner', 'Ninguno', 'd', 5, 'Finales', 'Ningún jugador ha logrado batir redes en tres finales. Cuatro leyendas consiguieron marcar en dos finales: Pelé (1958/1970), Vavá (1958/1962), Breitner (1974/1982) y Zidane (1998/2006).', true, false),
('¿Quién fue el primer jugador en salir del banquillo y marcar en una final de la Copa del Mundo?', 'Dick Nanninga', 'Mario Götze', 'Rudi Völler', 'Andreas Brehme', 'a', 5, 'Finales', 'El neerlandés Dick Nanninga ingresó como suplente en el Mundial de Argentina 1978 y mandó el encuentro a la prórroga tras batir de cabeza las redes argentinas en el minuto 82.', true, false),
('¿Qué equipo se mantuvo invicto en un Mundial pero fue eliminado en primera ronda?', 'Nueva Zelanda 2010', 'Camerún 1982', 'Italia 1966', 'Escocia 1974', 'a', 5, 'Curiosidades', 'La modesta selección de Nueva Zelanda igualó sus tres encuentros de grupos en Sudáfrica 2010 (ante Italia, Paraguay y Eslovaquia), quedando fuera en primera fase pese a ser el único equipo invicto del torneo.', true, false),
('¿Cuál fue el primer partido de la Copa del Mundo que se definió en tiempo extra?', 'Austria 3-2 Francia (1934)', 'Italia 2-1 España (1934)', 'Suiza 3-2 Países Bajos (1934)', 'Alemania 5-2 Bélgica (1934)', 'a', 5, 'Historia', 'En los octavos de final de Italia 1934, Austria y Francia empataron 1-1 en el tiempo reglamentario. En la prórroga, los austriacos se impusieron 3-2 en una definición inédita.', true, false),
('¿Cuántos goles marcó Gerd Müller en la fase de grupos del Mundial 1970?', '5', '6', '7', '8', 'c', 5, 'Goleadores', 'El ''Torpedo'' Gerd Müller comenzó a paso arrollador en México 1970, marcando 1 tanto ante Marruecos, un hat-trick contra Bulgaria y otro hat-trick histórico frente a Perú.', true, false),
('¿Qué técnico ha clasificado y dirigido a de cinco selecciones diferentes en la Copa del Mundo?', 'Carlos Alberto Parreira', 'Bora Milutinović', 'Guus Hiddink', 'Sven-Göran Eriksson', 'b', 5, 'Curiosidades', 'El carismático Bora Milutinović dirigió de forma consecutiva a México (1986), Costa Rica (1990), Estados Unidos (1994), Nigeria (1998) y China (2002).', true, false),
('¿Quién erró el primer penal en la primera tanda de desempate de una final?', 'Franco Baresi', 'Daniele Massaro', 'Roberto Baggio', 'Luís Figo', 'a', 5, 'Finales', 'El legendario capitán italiano Franco Baresi pateó por encima del larguero el primer lanzamiento de la fatídica tanda de penaltis de la final de EE. UU. 1994.', true, false),
('¿Quién anotó el gol número 500 en la historia de la Copa del Mundo?', 'Bobby Collins', 'Pelé', 'Just Fontaine', 'Vavá', 'a', 5, 'Récords', 'El escocés Bobby Collins anotó el gol 500 de las Copas del Mundo en la fase de grupos de Suecia 1958 durante la derrota de Escocia 3-2 ante Paraguay.', true, false),
('¿Quién ganó la Copa del Mundo de 1974?', 'Alemania Federal', 'Países Bajos', 'Brasil', 'Argentina', 'a', 1, 'Campeones', 'Alemania Federal aprovechó su localía para dar la sorpresa y derrotar 2-1 en la final a los revolucionarios Países Bajos comandados por Johan Cruyff.', true, false),
('¿Qué país fue sede del Mundial de 1962?', 'Chile', 'Argentina', 'Uruguay', 'Perú', 'a', 1, 'Sedes', 'Pese a sufrir el devastador terremoto de Valdivia de 1960, el pueblo de Chile se levantó y organizó con gran gallardía la séptima Copa Mundial de la FIFA.', true, false),
('¿Quién anotó el ''Gol del Siglo'' en México 1986?', 'Diego Maradona', 'Gary Lineker', 'Careca', 'Enzo Francescoli', 'a', 1, 'Momentos Históricos', 'Diego Armando Maradona eludió a cinco jugadores ingleses y al portero Shilton arrancando desde mitad de cancha, firmando la obra de arte más famosa del balompié mundial.', true, false),
('¿Cuántas selecciones compitieron en Uruguay 1930?', '13', '16', '8', '24', 'a', 1, 'Historia', 'Debido a las dificultades de transporte y la Gran Depresión económica, solo 13 selecciones acudieron al primer Mundial por invitation directa y sin fase clasificatoria.', true, false),
('¿Qué delantero brasileño es conocido como ''El Fenómeno''?', 'Ronaldo', 'Romário', 'Bebeto', 'Adriano', 'a', 1, 'Jugadores', 'Ronaldo Luís Nazário de Lima, apodado ''El Fenómeno'', asombró al mundo por su potencia física, desmarque y letal definición con el arco en la mira.', true, false),
('¿Cuál fue la mascot de Francia 1998?', 'Footix', 'Ciao', 'Naranjito', 'Pique', 'a', 1, 'Curiosidades', 'Footix era un colorido gallo azul y rojo con un balón de fútbol, representando el símbolo nacional y el ave tradicional de los campos franceses.', true, false),
('¿Quién es el máximo goleador argentino en la historia de los Mundiales?', 'Gabriel Batistuta', 'Lionel Messi', 'Diego Maradona', 'Mario Kempes', 'b', 1, 'Goleadores', 'Durante su triunfal participación en Qatar 2022, Lionel Messi superó los 10 goles marcados por Gabriel Batistuta para convertirse en el máximo artillero albiceleste con 13 dianas.', true, false),
('¿Qué selección ganó el Mundial de Corea/Japón 2002?', 'Brasil', 'Alemania', 'Turquía', 'Corea del Sur', 'a', 1, 'Campeones', 'Liderada por las genialidades del tridente de ataque ''Ronaldo, Rivaldo y Ronaldinho'', la escuadra brasileña ganó todos sus cotejos para alzar el trofeo del pentacampeonato.', true, false),
('¿En qué país se jugó la Copa del Mundo de 1966?', 'Inglaterra', 'Italia', 'Francia', 'Alemania', 'a', 1, 'Sedes', 'El certamen volvió al país que inventó el fútbol reglamentario, Inglaterra, en una edición muy recordada por jugarse en estadios tan icónicos como Wembley.', true, false),
('¿Quién anotó el primer hat-trick en un Mundial?', 'Bert Patenaude', 'Guillermo Stábile', 'Pedro Cea', 'Angelo Schiavio', 'a', 1, 'Goleadores', 'El estadounidense Bert Patenaude se adelantó a Guillermo Stábile por apenas unos días al anotar tres goles ante Paraguay en la fase de grupos del Mundial de Uruguay 1930.', true, false),
('¿Qué legendario delantero alemán marcó 14 goles en sus participaciones mundialistas?', 'Gerd Müller', 'Jürgen Klinsmann', 'Rudi Völler', 'Karl-Heinz Rummenigge', 'a', 1, 'Jugadores', 'Gerd ''El Torpedero'' Müller firmó un récord impresionante de 14 goles convertidos en solo dos mundiales disputados (10 anotaciones en 1970 y 4 goles decisivos en 1974).', true, false),
('¿Qué selección es conocida como ''La Celeste''?', 'Uruguay', 'Argentina', 'Brasil', 'Paraguay', 'a', 1, 'Selecciones', 'La selección charrúa de Uruguay recibe con orgullo este distintivo debido al color celeste de su casaca, utilizada desde un torneo disputado en el año 1910.', true, false),
('¿Cuál fue la mascota del Mundial de México 1970?', 'Juanito', 'Pique', 'Naranjito', 'Gauchito', 'a', 1, 'Curiosidades', 'Juanito era un sonriente niño vestido con la playera verde de México y un sombrero tradicional de paja que llevaba escrita la palabra del país anfitrión.', true, false),
('¿Quién anotó el gol del triunfo en la final de Italia 1990?', 'Andreas Brehme', 'Jürgen Klinsmann', 'Lothar Matthäus', 'Rudi Völler', 'a', 1, 'Finales', 'El defensor zurdo Andreas Brehme definió con sobria derecha un polémico penalti pitado en el minuto 85 de la final contra Argentina, otorgando a Alemania su tercera estrella.', true, false),
('¿En qué Mundial se jugó con el mítico balón Tango?', 'Argentina 1978', 'España 1982', 'México 1986', 'Alemania 1974', 'a', 1, 'Historia', 'El modelo ''Tango Durlast'' de Adidas revolucionó el diseño de los balones mundiales en Argentina 1978, convirtiéndose en el preferido de los aficionados por décadas.', true, false),
('¿Cuántas Copas del Mundo ha ganado Italia?', 'Italia', 'Argentina', 'Alemania', '4', 'd', 2, 'Campeones', 'La escuadra ''Azzurra'' es tetracampeona mundialista gracias a sus recordadas coronas alzadas en las ediciones de 1934, 1938, 1982 y la final de Alemania 2006.', true, false),
('¿Quién es el máximo goleador africano en Mundiales?', 'Asamoah Gyan', 'Didier Drogba', 'Samuel Eto''o', 'Riyad Mahrez', 'a', 2, 'Goleadores', 'El ariete ghanés Asamoah Gyan anotó un total de 6 goles en sus participaciones de 2006, 2010 y 2014, convirtiéndose en el mayor romperredes del continente africano.', true, false),
('¿Qué país organizó el Mundial 1982?', 'España', 'Italia', 'Francia', 'Portugal', 'a', 2, 'Sedes', 'España fue el país anfitrión en 1982, acogiendo un certamen de vanguardia que amplió la participación de países a un total de 24 selecciones en estadios históricos.', true, false),
('¿Qué selecciones protagonizaron la ''Batalla de Santiago'' en 1962?', 'Chile e Italia', 'Brasil y Chile', 'Argentina y Uruguay', 'Italia y Brasil', 'a', 2, 'Momentos Históricos', 'Este rudo e histórico partido de fase de grupos destacó por la violencia sin precedentes en el terreno de juego, requiriendo de reiteradas intervenciones de la policía chilena.', true, false),
('¿Quién fue el portero campeón con Italia en Alemania 2006?', 'Gianluigi Buffon', 'Francesco Toldo', 'Angelo Peruzzi', 'Dino Zoff', 'a', 2, 'Jugadores', 'Gianluigi Buffon tenido una actuación inolvidable en 2006; sus magistrales atajadas y su sobria capitanía fueron fundamentales para que Italia alzara la copa en Berlín.', true, false),
('¿Qué trofeo reemplazó al Jules Rimet en 1974?', 'El actual Trofeo de la Copa Mundial de la FIFA', 'La Copa de Oro', 'El Balón de Oro', 'La Copa Intercontinental', 'a', 2, 'Curiosidades', 'Tras adjudicarse definitivamente Brasil la copa original Jules Rimet, la FIFA introdujo el majestuoso modelo actual diseñado con dos figuras alzando el planeta Tierra.', true, false),
('¿Quién anotó el primer gol de la final de México 1986?', 'José Luis Brown', 'Jorge Valdano', 'Diego Maradona', 'Sergio Almirón', 'a', 2, 'Finales', 'El defensor albiceleste José Luis ''Tata'' Brown abrió con orgullo la cuenta para Argentina tras clavar un gran frentazo a la red en el primer tiempo del choque con Alemania.', true, false),
('¿En qué Mundial se jugó por primera vez la fase de octavos de final?', '1986', '1982', '1990', '1974', 'a', 2, 'Historia', 'La FIFA reestructuró el formato de competición en México 1986, eliminando la fase de grupos secundaria para instaurar la emocionante fase de eliminación directa desde octavos de final.', true, false),
('¿Qué selección es conocida como ''Los Leones Indomables''?', 'Camerún', 'Nigeria', 'Senegal', 'Ghana', 'a', 2, 'Selecciones', 'Este imponente apodo fue acuñado en la década de 1970 por decreto presidencial en Camerún, para destacar la ferocidad y combatividad de su equipo.', true, false),
('¿Quién anotó en todos los partidos que disputó su selección en un mismo Mundial (6)?', 'Jairzinho (1970)', 'Just Fontaine (1958)', 'Gerd Müller (1974)', 'Paolo Rossi (1982)', 'a', 2, 'Récords', 'En el caluroso Mundial de México 1970, el astro brasileño Jairzinho asombró a todos al marcar goles en cada uno de los 6 cotejos que disputó la inolvidable selección del ''Scratch du Oro''.', true, false),
('¿Cuál de estas selecciones ganó el Mundial en su primera participación?', 'Uruguay e Italia', 'Uruguay', 'Italia', 'Ninguna', 'a', 2, 'Campeones', 'Uruguay ganó el primer Mundial disputado en su territorio en 1930, mientras que Italia se coronó campeona en su propio suelo en la segunda edición del campeonato en 1934.', true, false),
('¿Quién fue el máximo goleador del Mundial 1982?', 'Paolo Rossi', 'Diego Maradona', 'Karl-Heinz Rummenigge', 'Zico', 'a', 2, 'Goleadores', 'El astuto Paolo Rossi retornó tras una dura sanción para marcar 6 goles vitales (incluyendo un triplete memorable a Brasil) que llevaron a Italia a la gloria en España 1982.', true, false),
('¿En qué país se celebró el Mundial 1938?', 'Francia', 'Italia', 'Alemania', 'Bélgica', 'a', 2, 'Sedes', 'La tercera Copa del Mundo se disputó en Francia, un certamen ensombrecido por el inminente estallido de la Segunda Guerra Mundial en el continente europeo.', true, false),
('¿Quién es el máximo goleador de Inglaterra en Copas del Mundo?', 'Gary Lineker', 'Bobby Charlton', 'Wayne Rooney', 'Harry Kane', 'a', 2, 'Jugadores', 'El elegante delantero de área Gary Lineker es el máximo goleador de los ''Tres Leones'' en Mundiales con 10 anotaciones (6 goles en México 1986 y 4 dianas en Italia 1990).', true, false),
('¿Cómo se llamó el balón oficial del Mundial 2010?', 'Jabulani', 'Teamgeist', 'Brazuca', 'Telstar', 'a', 2, 'Curiosidades', 'El Jabulani (''celebrar'' en zulú) causó gran polémica por su trayectoria aérea errática e impredecible que puso en graves dificultades a los porteros participantes.', true, false),
('¿Quién marcó el gol de la victoria para Alemania en la final de 2014?', 'Mario Götze', 'Thomas Müller', 'Bastian Schweinsteiger', 'André Schürrle', 'a', 3, 'Finales', 'El talentoso Mario Götze controló de pecho un centro al área y definió de volea en el minuto 113 de la prórroga ante Argentina, coronando a Alemania campeona.', true, false),
('¿Qué país fue el primer anfitrión en no superar la fase de grupos?', 'Sudáfrica (2010)', 'Catar (2022)', 'Estados Unidos (1994)', 'Japón (2002)', 'a', 3, 'Historia', 'A pesar de todo el color de las ''vuvuzelas'' y el apoyo del público, la selección de Sudáfrica no pudo avanzar a octavos de final tras de empatar con México, perder con Uruguay y batir a Francia.', true, false),
('¿Quién es el máximo goleador de Mundiales con una selección que nunca ha sido campeona?', 'Sándor Kocsis', 'Just Fontaine', 'Eusébio', 'Thomas Müller', 'a', 3, 'Goleadores', 'El letal ''Cabecita de Oro'' húngaro, Sándor Kocsis, anotó la asombrosa cantidad de 11 goles en solo cinco partidos disputados de la mítica edición de Suiza 1954.', true, false),
('¿Qué selección asiática fue la primera en alcanzar los cuartos de final?', 'Corea del Norte (1966)', 'Japón (2002)', 'Corea del Sur (2002)', 'Arabia Saudita (1994)', 'a', 3, 'Selecciones', 'En el Mundial de Inglaterra 1966, la modesta Corea del Norte conmocionó al fútbol internacional al vencer 1-0 a Italia en primera ronda y clasificar a los cuartos de final.', true, false),
('¿En qué partido se registró la mayor asistencia de público en la historia de los Mundiales?', 'Uruguay vs Brasil (1950)', 'Brasil vs Italia (1970)', 'Argentina vs Países Bajos (1978)', 'Alemania vs Argentina (1986)', 'a', 3, 'Récords', 'Se estima que cerca de 200.000 aficionados colmaron el inconcluso Estadio de Maracaná para presenciar la histórica definición del Maracanazo en tierras brasileñas.', true, false),
('¿En qué Mundial se implementó la espuma desaparecedora en los tiros libres?', 'Brasil 2014', 'Sudáfrica 2010', 'Rusia 2018', 'Catar 2022', 'a', 3, 'Curiosidades', 'La FIFA adoptó oficialmente este invento en Brasil 2014 para garantizar que los defensores respetaran fielmente la distancia reglamentaria de la barrera de juego.', true, false),
('¿Qué partido es conocido como ''El Milagro de Berna''?', 'Final 1954: Alemania vs Hungría', 'Semifinal 1970: Italia vs Alemania', 'Final 1966: Inglaterra vs Alemania', 'Cuartos 1958: Brasil vs Gales', 'a', 3, 'Momentos Históricos', 'Se denominó así porque Alemania Federal, un humilde y amateur equipo de posguerra, derrotó 3-2 en la final a los todopoderosos ''Magiares Mágicos'' de Hungría en Suiza 1954.', true, false),
('¿En qué ciudad se disputó la final de la Copa del Mundo de 1994?', 'Pasadena (Los Ángeles)', 'Dallas', 'Chicago', 'Nueva York', 'a', 3, 'Sedes', 'El histórico estadio Rose Bowl de la ciudad de Pasadena, California, albergó la gran final que coronó a Brasil campeón frente a Italia en la tanda de penaltis.', true, false),
('¿Cuál fue el primer Mundial que permitió un cuarto cambio en el tiempo extra?', 'Rusia 2018', 'Brasil 2014', 'Catar 2022', 'Alemania 2006', 'a', 3, 'Historia', 'La IFAB autorizó esta regla para aliviar el desgaste físico extremo de los jugadores de campo en las disputadas prórrogas del Mundial de Rusia 2018.', true, false),
('¿Cuántas selecciones participaron en el Mundial 1982?', '24', '16', '20', '32', 'a', 3, 'Sedes', 'El certamen de España 1982 amplió su formato de 16 a 24 selecciones para otorgar mayores posibilidades de competir a las federaciones del resto del planeta.', true, false),
('¿Qué jugador brasileño disputó tres finales consecutivas (1994, 1998, 2002)?', 'Cafú', 'Roberto Carlos', 'Ronaldo', 'Rivaldo', 'a', 3, 'Jugadores', 'El incansable lateral brasileño Marcos Evangelista de Moras, ''Cafú'', ostenta la legendaria marca de jugar tres finales mundiales al hilo, ganando las de 1994 y 2002.', true, false),
('¿Quién fue el máximo goleador del Mundial 1950?', 'Ademir', 'Estanislao Basora', 'Alcides Ghiggia', 'Óscar Míguez', 'a', 3, 'Goleadores', 'El delantero brasileño Ademir Marques de Menezes anotó un total de 8 goles en el torneo de 1950, de los cuales cuatro fueron convertidos en un mismo cotejo frente a Suecia.', true, false),
('¿En qué Mundial se introdujo por primera vez una mascota?', '1966', '1970', '1974', '1962', 'a', 3, 'Curiosidades', 'Inglaterra 1966 innovó la imagen mercadológica de los mundiales al presentar a ''Willie'', un tierno león futbolista que lucía con orgullo la bandera del Reino Unido.', true, false),
('¿Cuál es la única selección que ha perdido tres finales sin haber ganado ninguna?', 'Países Bajos', 'Hungría', 'Checoslovaquia', 'Argentina', 'a', 3, 'Selecciones', 'La apodada ''Naranja Mecánica'' cayó en las finales de Alemania Federal 1974, Argentina 1978 y Sudáfrica 2010, ganándose la reputación del campeón sin corona de la historia.', true, false),
('¿Quién anotó el gol de la victoria en la final de 1950?', 'Alcides Ghiggia', 'Juan Alberto Schiaffino', 'Ademir', 'Zizinho', 'a', 3, 'Finales', 'El veloz Alcides Ghiggia batió al guardameta brasileño Moacir Barbosa en el minuto 79 del Maracanazo, sellando el histórico 2-1 definitivo que enmudeció a todo Brasil.', true, false),
('¿Cuántos goles anotó Hungría en la fase de grupos del Mundial 1954?', '17', '9', '15', '11', 'a', 3, 'Récords', 'La ofensiva húngara arrolló a Corea del Sur 9-0 y a Alemania Federal 8-3, estableciendo un asombroso registro anotador que se mantiene imbatible para una fase de grupos.', true, false),
('¿Quién fue el único jugador en anotar un gol olímpico en la Copa del Mundo?', 'Marcos Coll', 'Diego Maradona', 'Roberto Carlos', 'David Beckham', 'a', 4, 'Curiosidades', 'El colombiano Marcos Coll grabó con oro su nombre en Chile 1962 al batir al legendario guardameta soviético Lev Yashin directo de un tiro de esquina.', true, false),
('¿Qué selección ha ganado más partidos en la historia de los Mundiales?', 'Brasil', 'Alemania', 'Argentina', 'Italia', 'a', 4, 'Récords', 'Brasil lidera holgadamente el histórico de victorias en los mundiales con un total de 76 triunfos acumulados desde la edición inicial del torneo de 1930.', true, false),
('¿Cuál fue el primer Mundial con 32 selecciones?', 'Francia 1998', 'Estados Unidos 1994', 'Italia 1990', 'México 1986', 'a', 4, 'Historia', 'Francia 1998 fue la edición inaugural con el formato expandido de 32 selecciones nacionales, lo que propició el debut de países como Jamaica, Japón y Croacia.', true, false),
('¿Quién detuvo tres penaltis en una misma tanda mundialista?', 'Ricardo (Portugal, 2006)', 'Danijel Subašić (Croacia, 2018)', 'Sergio Goycochea (Argentina, 1990)', 'Harald Schumacher (Alemania, 1982)', 'a', 4, 'Jugadores', 'El meta luso Ricardo atajó tres disparos de Inglaterra en la tanda de cuartos de final de Alemania 2006, una hazaña posteriormente igualada por Subašić en 2018.', true, false),
('¿Qué selección anotó 27 goles en una sola edición de la Copa del Mundo?', 'Hungría (1954)', 'Brasil (1950)', 'Alemania (2014)', 'Francia (1998)', 'a', 4, 'Goleadores', 'La demoledora selección de Hungría, apodada los ''Magiares Mágicos'', anotó la friolera de 27 tantos en Suiza 1954 a pesar de perder la gran final.', true, false),
('¿Cuál fue el primer Mundial organizado por dos países?', 'Corea del Sur y Japón 2002', 'Estados Unidos y Canadá 2026', 'México y Estados Unidos 1994', 'Bélgica y Países Bajos 2000', 'a', 4, 'Sedes', 'La Copa Mundial de Corea-Japón 2002 rompió moldes al celebrarse conjuntamente por primera vez en dos países, así como el primer torneo en jugarse en suelo asiático.', true, false),
('¿En qué final un defensor anotó el único gol del partido?', '1990 (Andreas Brehme)', '1998 (Zinedine Zidane)', '1974 (Gerd Müller)', '2010 (Andrés Iniesta)', 'a', 4, 'Finales', 'En la ruda final de Italia 1990, el zaguero germano Andreas Brehme anotó de tiro penal el único gol con el que Alemania derrotó a la selección de Argentina.', true, false),
('¿Quién fue el primer jugador en disputar un Mundial con dos selecciones diferentes?', 'Luis Monti', 'Alfredo Di Stéfano', 'Dejan Stanković', 'Robert Prosinečki', 'a', 4, 'Jugadores', 'El implacable mediocampista Luis Monti disputó el Mundial de 1930 con su natal Argentina y posteriormente se nacionalizó italiano para jugar y coronarse campeón con la Azzurra en 1934.', true, false),
('¿Cuántas tarjetas rojas se mostraron en el partido Portugal vs Países Bajos 2006?', '4', '2', '3', '5', 'a', 4, 'Récords', 'El árbitro ruso Valentín Ivanov expulsó a dos futbolistas de cada bando (Costinha y Deco por Portugal; Boulahrouz y van Bronckhorst por Países Bajos) en el partido con más tarjetas rojas de la historia.', true, false),
('¿Qué país ha sido subcampeón mundialista más veces sin ser campeón?', 'Países Bajos', 'Hungría', 'Checoslovaquia', 'Suecia', 'a', 4, 'Selecciones', 'La talentosa selección de los Países Bajos ostenta el récord amargo de disputar tres finales (1974, 1978 y 2010) y salir derrotada en todas las ocasiones.', true, false),
('¿En qué Mundial se produjo la primera expulsión en una final?', '1990 (Pedro Monzón)', '2006 (Zinedine Zidane)', '1994 (Gianluca Pagliuca)', '1982 (Claudio Gentile)', 'a', 4, 'Finales', 'El defensa argentino Pedro Monzón, que había ingresado de cambio en el entretiempo, fue expulsado en el minuto 65 tras una falta sobre Jürgen Klinsmann en la final de Italia 1990.', true, false),
('¿Quién fue el máximo goleador del Mundial 1998?', 'Davor Šuker', 'Ronaldo', 'Gabriel Batistuta', 'Dennis Bergkamp', 'a', 4, 'Goleadores', 'El delantero croata Davor Šuker firmó una de las mejores actuaciones individuales de Francia 1998 anotando 6 goles históricos que metieron a Croacia en el podio.', true, false),
('¿Cuál fue la primera Copa del Mundo en la que se utilizó el balón con diseño de pentágonos negros?', '1970 (Telstar)', '1966 (Challenge 4-Star)', '1974 (Telstar Durlast)', '1978 (Tango)', 'a', 4, 'Historia', 'El icónico balón Adidas ''Telstar'' debutó en México 1970; su diseño de 32 paneles en blanco y negro facilitó su visibilidad por televisión.', true, false),
('¿Qué jugador tiene el récord de más partidos disputados en Mundiales sin marcar un gol?', 'Paolo Maldini', 'Lothar Matthäus', 'Miroslav Klose', 'Cafú', 'a', 4, 'Jugadores', 'El legendario defensor italiano Paolo Maldini disputó un impresionante total de 23 compromisos mundialistas entre 1990 y 2002 sin lograr mandar el esférico a las redes.', true, false),
('¿Cuántos goles en propia puerta se marcaron en el Mundial 2018, récord del torneo?', '12', '6', '9', '15', 'a', 4, 'Curiosidades', 'El certamen de Rusia 2018 estableció la inusual plusmarca de 12 autogoles anotados en una sola edición, duplicando el récord previo que ostentaba Francia 1998.', true, false),
('¿Qué selección campeona anotó solo 8 goles en todo el torneo?', 'España (2010)', 'Italia (2006)', 'Francia (1998)', 'Inglaterra (1966)', 'a', 4, 'Récords', 'Haciendo gala de un pragmatismo y control de juego total, la selección española conquistó Sudáfrica 2010 con apenas 8 goles anotados en sus siete compromisos.', true, false),
('¿Quién fue el primer futbolista en participar en cinco Copas del Mundo?', 'Antonio Carbajal', 'Lothar Matthäus', 'Gianluigi Buffon', 'Lionel Messi', 'a', 4, 'Jugadores', 'El guardameta mexicano Antonio ''La Tota'' Carbajal estableció esta mítica marca de longevidad al atajar con su selección en los Mundiales de 1950, 1954, 1958, 1962 y 1966.', true, false),
('¿Cuántos penaltis falló Italia en la tanda de la final de 1994?', '3', '2', '1', '4', 'a', 4, 'Finales', 'La selección azzurra vio esfumarse el trofeo en Pasadena luego de que los astros Franco Baresi, Daniele Massaro y finalmente Roberto Baggio erraran sus lanzamientos frente a Brasil.', true, false),
('¿En qué Mundial se registró la goleada 10-1 a favor de Hungría?', '1982', '1954', '1974', '1966', 'a', 4, 'Historia', 'Ocurrió en la fase de grupos del Mundial de España 1982, donde la potentísima Hungría le propinó un histórico e incontestable 10-1 a la desahuciada selección de El Salvador.', true, false),
('¿Qué portero capitán levantó el trofeo en el Mundial 2010?', 'Iker Casillas', 'Gianluigi Buffon', 'Manuel Neuer', 'Hugo Lloris', 'a', 4, 'Jugadores', 'El portero Iker Casillas portó con distinción el brazalete de la ''Roja'' en Sudáfrica 2010, ganándose su rol de líder indiscutible gracias a salvadas memorables en cuartos de final y en la final ante Robben.', true, false),
('¿Quién anotó el gol más rápido en la historia de los Mundiales en tiempo extra?', 'Abdelmoumene Djabou', 'Clint Dempsey', 'Rudi Völler', 'Mario Götze', 'a', 4, 'Récords', 'El argelino Abdelmoumene Djabou anotó un gol histórico a Alemania en Brasil 2014 al rematar al arco a los 120 minutos y 58 segundos de la prórroga de octavos de final.', true, false),
('¿Cuál fue el primer Mundial con transmisión en color para todo el planeta?', '1970', '1974', '1978', '1966', 'a', 4, 'Historia', 'México 1970 fue un certamen vanguardista en telecomunicaciones al emitirse con éxito en directo y a todo color gracias al uso pionero de satélites espaciales.', true, false),
('¿Quién fue el máximo asistente de la Copa del Mundo 1986?', 'Diego Maradona', 'Jorge Burruchaga', 'Gary Lineker', 'Preben Elkjær', 'a', 5, 'Goleadores', 'Diego Armando Maradona dio un recital absoluto en México 1986 al firmar un total de 5 asistencias en el certamen, incluyendo el mítico pase de gol a Burruchaga en el triunfo final por 3-2 sobre Alemania.', true, false),
('¿En qué Mundial se jugó la primera final definida en tiempo extra?', '1934', '1930', '1938', '1950', 'a', 5, 'Finales', 'Ocurrió en el Mundial de Italia 1934, donde los italianos terminaron empatados 1-1 en los 90 minutos reglamentarios ante Checoslovaquia, prevaleciendo 2-1 gracias a un gol de Schiavio en la prórroga.', true, false),
('¿Cuál es el récord de imbatibilidad en minutos de un portero en Mundiales?', '517 (Walter Zenga)', '559 (Pascal Zuberbühler)', '500 (Gianluigi Buffon)', '400 (Iker Casillas)', 'a', 5, 'Récords', 'El italiano Walter Zenga mantuvo su arco invicto durante 517 minutos consecutivos en Italia 1990, hasta que el delantero argentino Claudio Caniggia rompió la racha de cabeza en semifinales.', true, false),
('¿Quién marcó el gol número 2000 en la historia de la Copa del Mundo?', 'Marcus Allbäck', 'Miroslav Klose', 'Ronaldo', 'Andriy Shevchenko', 'a', 5, 'Curiosidades', 'El sueco Marcus Allbäck firmó este gol hito durante el Mundial de Alemania 2006, marcando de cabeza en un emocionante encuentro que acabó en empate 2-2 con Inglaterra.', true, false),
('¿Qué selección fue la primera en ganar el Mundial sin haber sido anfitriona?', 'Italia (1938)', 'Uruguay (1930)', 'Brasil (1958)', 'Alemania (1954)', 'a', 5, 'Campeones', 'La Azzurra, comandada por el gran director técnico Vittorio Pozzo, defendió su corona conquistada en 1934 al consagrarse campeona en suelo francés en el Mundial de 1938.', true, false),
('¿Cuántos goles anotó Sándor Kocsis en el Mundial 1954?', '11', '10', '13', '9', 'a', 5, 'Goleadores', 'El estelar delantero húngaro Sándor Kocsis deslumbró al mundo entero al anotar 11 goles de gran factura técnica en apenas cinco encuentros con el ''Equipo de Oro''.', true, false),
('¿En qué edición de la Copa del Mundo se estrenó el sistema de ''gol de oro''?', '1998', '1994', '2002', '1990', 'a', 5, 'Historia', 'El ''gol de oro'' debutó en Francia 1998; el defensa francés Laurent Blanc se convirtió en el primer jugador de la historia en anotar un tanto bajo esta muerte súbita para eliminar a Paraguay en octavos de final.', true, false),
('¿Quién fue el primer jugador en ser expulsado en dos Mundiales diferentes?', 'Rigobert Song', 'Zinedine Zidane', 'Claudio Gentile', 'David Beckham', 'a', 5, 'Jugadores', 'El temperamental defensa de Camerún, Rigobert Song, vio la tarjeta roja por primera vez ante Brasil en el Mundial de 1994, y volvió a repetir expulsión ante Chile en Francia 1998.', true, false),
('¿Qué partido ostenta el récord de más goles en un solo Mundial con prórroga?', 'Austria 7-5 Suiza (1954)', 'Brasil 6-5 Polonia (1938)', 'Alemania 4-3 Inglaterra (1970)', 'Italia 4-3 Alemania (1970)', 'a', 5, 'Récords', 'El Austria contra Suiza en 1954 se resolvió en tiempo regular con un impactante 7-5, lo que lo convierte en el partido con más goles anotados en toda la historia de las Copas del Mundo.', true, false),
('¿Cuál fue el primer país en organizar un Mundial sin ser fundador de la FIFA?', 'Uruguay (1930)', 'Italia (1934)', 'Francia (1938)', 'Brasil (1950)', 'a', 5, 'Sedes', 'Uruguay no se encontraba entre las siete naciones europeas fundadoras de la FIFA en 1904, pero se le otorgó con total justicia el honor de organizar el certamen inaugural de 1930 por ser bicampeón olímpico.', true, false),
('¿Anote el gol más tardío en un partido de fase de grupos en la historia del torneo?', 'Abdelmoumene Djabou', 'John Aloisi', 'Nelson Cuevas', 'Oleg Salenko', 'a', 5, 'Récords', 'El atacante argelino Abdelmoumene Djabou batió de forma histórica al guardameta alemán Manuel Neuer a los 120 minutos y 58 segundos de juego en el dramático duelo de octavos de Brasil 2014.', true, false),
('¿Cuántos hat-tricks se registraron en la Copa del Mundo 2022?', '2', '3', '1', '4', 'a', 5, 'Curiosidades', 'Únicamente el portugués Gonçalo Ramos (contra Suiza en octavos) y el francés Kylian Mbappé (contra Argentina en la gran final) consiguieron marcar tres goles en un mismo cotejo en Qatar 2022.', true, false),
('¿Quién fue el máximo goleador de la fase de grupos del Mundial 1970?', 'Gerd Müller', 'Pelé', 'Jairzinho', 'Uwe Seeler', 'a', 5, 'Goleadores', 'El implacable ''Torpedo'' Gerd Müller inició el torneo de México 1970 con un ritmo frenético, anotando un espectacular total de 7 goles en los tres partidos disputados de la fase de grupos.', true, false),
('¿En qué edición se introdujo el requisito de que el balón debía ser esférico?', '1930', '1934', '1938', '1950', 'a', 5, 'Historia', 'Ocurrió en la accidentada final de Uruguay 1930, donde al haber disputas por qué balón usar, se formalizó el reglamento de usar esféricos uniformes tras jugar el primer tiempo con el de Argentina y el segundo con el de Uruguay.', true, false),
('¿Cuál fue el primer Mundial en el que todos los estadios fueron completamente nuevos?', 'Catar 2022', 'Japón/Corea 2002', 'Alemania 2006', 'Sudáfrica 2010', 'a', 5, 'Sedes', 'Qatar 2022 rompió moldes al edificar prácticamente toda su infraestructura deportiva desde cero, inaugurando siete modernos coliseos futuristas para albergar el certamen.', true, false),
('¿Quién fue el primer jugador en anotar en cinco partidos consecutivos en un mismo Mundial?', 'Just Fontaine', 'Jairzinho', 'Gerd Müller', 'Paolo Rossi', 'a', 5, 'Récords', 'El goleador francés Just Fontaine fue el primero en conseguir este hito anotando en los primeros cinco cotejos que jugó con Francia en el asombroso Mundial de Suecia 1958.', true, false),
('¿Cuántos penaltis marcó Eusébio en el Mundial 1966?', '4', '3', '2', '5', 'a', 5, 'Goleadores', 'La estrella portuguesa Eusébio demostró un pulso de hierro al ejecutar y anotar con éxito 4 tiros penaltis en Inglaterra 1966, lo que impulsó a Portugal hasta las semifinales.', true, false),
('¿Qué selección es la única que ha terminado un Mundial sin recibir un solo gol?', 'Suiza 2006', 'Italia 2006', 'Brasil 1994', 'Alemania 2014', 'a', 5, 'Récords', 'Suiza defendió de forma invicta su valla en Alemania 2006, logrando quedar eliminada en octavos ante Ucrania sin encajar goles en el tiempo reglamentario de sus partidos.', true, false),
('¿En qué final un jugador marcó un hat-trick en tiempo reglamentario?', 'Inglaterra 1966', 'Brasil 1958', 'Alemania 1954', 'Francia 1998', 'a', 5, 'Finales', 'El inglés Geoff Hurst marcó tres goles históricos a Alemania Occidental en la final de Inglaterra 1966, de los cuales dos fueron anotados en la prórroga del disputado cotejo.', true, false),
('¿Quién fue el máximo goleador del Mundial 1934?', 'Oldřich Nejedlý', 'Angelo Schiavio', 'Raimundo Orsi', 'Edmund Conen', 'a', 5, 'Goleadores', 'El veloz atacante checoslovaco Oldřich Nejedlý anotó de forma verídica 5 goles en el certamen de Italia 1934, una cifra que la FIFA certificó oficialmente de forma retroactiva en el año 2006.', true, false),
('¿Cuál fue el primer Mundial en el que se numeraron las camisetas de manera obligatoria?', '1954', '1950', '1958', '1962', 'a', 5, 'Historia', 'El torneo de Suiza 1954 marcó un gran paso adelante en la identificación de los atletas al estipularse de forma oficial la obligatoriedad de usar dorsales numerados en las playeras.', true, false),
('¿Qué país ganó la Copa del Mundo de 1958?', 'Brasil', 'Suecia', 'Francia', 'Alemania Federal', 'a', 1, 'Campeones', 'La mítica ''Seleção'' brasileña de Pelé y Garrincha conquistó con maestría su primera Copa Mundial en tierras escandinavas, venciendo 5-2 al país anfitrión de Suecia en la gran final.', true, false),
('¿En qué ciudad se inauguró el primer Mundial in 1930?', 'Montevideo', 'Buenos Aires', 'Río de Janeiro', 'Santiago', 'a', 1, 'Sedes', 'La hermosa e histórica ciudad de Montevideo, capital de Uruguay, acogió íntegramente todos los encuentros del certamen inaugural del campeonato mundialista en tres estadios diferentes.', true, false),
('¿Quién es el máximo goleador alemán en la historia de los Mundiales?', 'Miroslav Klose', 'Gerd Müller', 'Jürgen Klinsmann', 'Thomas Müller', 'a', 1, 'Goleadores', 'Miroslav Klose batió todos los registros germanos al firmar un total de 16 dianas a lo largo de cuatro certámenes mundiales seguidos (2002, 2006, 2010 y 2014).', true, false),
('¿Qué jugador es conocido como ''La Pulga''?', 'Lionel Messi', 'Diego Maradona', 'Pelé', 'Johan Cruyff', 'a', 1, 'Jugadores', 'Lionel Andrés Messi recibió con agrado el entrañable mote de ''La Pulga'' en su infancia y adolescencia debido a su baja estatura combinada con su inverosímil velocidad y gran regate.', true, false),
('¿En qué Mundial se jugó la semifinal conocida como ''El Partido del Siglo'' (Italia 4-3 Alemania Federal)?', 'México 1970', 'Alemania 1974', 'Argentina 1978', 'España 1982', 'a', 1, 'Momentos Históricos', 'Ocurrió en el mítico Estadio Azteca durante las semifinales de México 1970; Italia y Alemania Federal disputaron una agónica e inolvidable prórroga de de cinco goles que acabó en el histórico 4-3.', true, false),
('--Qué selección ganó la Copa del Mundo en 1998?', 'Francia', 'Brasil', 'Croacia', 'Países Bajos', 'a', 1, 'Campeones', 'Francia aprovechó de gran forma su localía en el certamen de 1998 al vapulear 3-0 en la gran final a Brasil, bordando con orgullo su primera estrella en la camiseta nacional.', true, false),
('¿Cuál fue la mascota del Mundial de Italia 1990?', 'Ciao', 'Pique', 'Footix', 'Naranjito', 'a', 1, 'Curiosidades', 'Ciao era una vanguardista mascota geométrica abstracta inspirada en un futbolista construido con barras tricolores de la bandera italiana, que llevaba un balón por cabeza.', true, false),
('¿Quién fue el máximo goleador del Mundial 2018?', 'Harry Kane', 'Kylian Mbappé', 'Antoine Griezmann', 'Romelu Lukaku', 'a', 1, 'Goleadores', 'El imponente ariete inglés Harry Kane se alzó con la prestigiada Bota de Oro de Rusia 2018 al marcar 6 goles de juego para los ''Tres Leones'' en el torneo.', true, false),
('¿En qué país se jugó el Mundial 1934?', 'Italia', 'Francia', 'Alemania', 'Suiza', 'a', 1, 'Sedes', 'La segunda Copa Mundial se celebró bajo la tensa atmósfera de la Italia de entreguerras, donde la selección anfitriona se adjudicó con pundonor su primera corona mundial.', true, false),
('¿Quién anotó dos goles en la final del Mundial 1978?', 'Mario Kempes', 'Daniel Bertoni', 'Leopoldo Luque', 'René Houseman', 'a', 1, 'Finales', 'El ''Matador'' Mario Alberto Kempes se consagró héroe nacional al marcar un soberbio doblete en la prórroga de la final de 1978 disputada frente a los Países Bajos.', true, false),
('¿Qué selección es conocida como ''La Roja''?', 'España', 'Chile', 'Portugal', 'Bélgica', 'a', 1, 'Selecciones', 'La selección española de fútbol adoptó este arraigado apodo histórico a raíz de la icónica playera roja con la que debutó en los Juegos Olímpicos de Amberes de 1920.', true, false),
('¿En qué estadio se jugó la final del Mundial 2014?', 'Maracaná', 'Morumbi', 'Mané Garrincha', 'Arena Corinthians', 'a', 1, 'Sedes', 'El legendario Estadio de Maracaná, en la ciudad de Río de Janeiro, acogió la disputada final en la que la poderosa selección alemana batió 1-0 en la prórroga a la Albiceleste.', true, false),
('¿Quién fue el capitán de Brasil en el Mundial 2002?', 'Cafú', 'Roberto Carlos', 'Ronaldo', 'Rivaldo', 'a', 1, 'Jugadores', 'El veloz e incansable lateral derecho Cafú capitaneó al plantel pentacampeón, pasando a la historia por subirse a la mesa del podio y alzar la copa con total algarabía.', true, false),
('¿Cuántos títulos mundiales tiene Alemania?', '4', '3', '5', '2', 'a', 1, 'Campeones', 'Alemania es una súper potencia mundialista al contar en sus vitrinas con cuatro trofeos de campeón de la FIFA, logrados en las ediciones de 1954, 1974, 1990 y Brasil 2014.', true, false),
('¿Qué país africano fue el primer anfitrión en no superar la fase de grupos?', 'Marruecos', 'Ghana', 'Senegal', 'Camerún', 'a', 1, 'Selecciones', 'Marruecos fue el primer anfitrión africano de la fase final de la Copa del Mundo en lograr clasificar.', true, false),
('¿Quién fue el máximo goleador del Mundial 1966?', 'Eusébio', 'Geoff Hurst', 'Bobby Charlton', 'Franz Beckenbauer', 'a', 2, 'Goleadores', 'La legendaria ''Pantera de Mozambique'', Eusébio da Silva Ferreira, deslumbró en tierras británicas al comandar la tabla de goleo con un espectacular total de 9 dianas convertidas.', true, false),
('¿En qué Mundial se permitió por primera vez la sustitución de jugadores?', '1970', '1966', '1974', '1962', 'a', 2, 'Historia', 'La FIFA introdujo la posibilidad de hacer dos cambios por partido en México 1970; el centrocampista soviético Anatoli Puzach pasó a los libros de historia al ser el primer sustituto verificado.', true, false),
('¿Cuál fue el país anfitrión del Mundial 1950?', 'Brasil', 'Uruguay', 'Argentina', 'México', 'a', 1, 'Sedes', 'Brasil organizó con asombrosa inversión el certamen de 1950, edificando expresamente para el certamen el gigantesco y colosal coliseo de Maracaná.', true, false),
('¿Quién anotó el famoso ''Gol Fantasma'' en la final de 1966?', 'Geoff Hurst', 'Bobby Charlton', 'Martin Peters', 'Roger Hunt', 'a', 1, 'Momentos Históricos', 'El delantero inglés Geoff Hurst ejecutó un potente remate en la prórroga que dio en el larguero y botó sobre la línea; el árbitro validó la acción en una de las jugadas más controvertidas de la historia.', true, false),
('¿Qué jugador brasileño marcó 15 goles en Copas del Mundo?', 'Ronaldo', 'Pelé', 'Vavá', 'Jairzinho', 'a', 1, 'Goleadores', 'Ronaldo ''El Fenómeno'' asombró en las Copas del Mundo al marcar un gran acumulado de 15 goles históricos a lo largo de tres espectaculares ediciones (1998, 2002 y 2006).', true, false),
('¿Cuál fue la mascota del Mundial de Rusia 2018?', 'Zabivaka', 'Fuleco', 'Footix', 'Willie', 'a', 1, 'Curiosidades', 'Zabivaka, cuyo entrañable nombre se traduce del ruso como ''el que anota'', era un lobo siberiano de aspecto alegre que lucía unas modernas gafas deportivas de protección.', true, false),
('¿En qué Mundial participaron 16 selecciones por primera vez?', '1934', '1954', '1950', '1930', 'a', 2, 'Historia', 'La FIFA adoptó formalmente el cupo cerrado de 16 equipos para disputar la fase final en Italia 1934, requiriendo de una fase previa clasificatoria para dirimir a los países competidores.', true, false),
('¿Quién es el máximo goleador de Portugal en Mundiales?', 'Eusébio', 'Cristiano Ronaldo', 'Pauleta', 'Luís Figo', 'a', 2, 'Goleadores', 'A pesar de disputar solamente la mítica edición de Inglaterra 1966, el estelar Eusébio se mantiene en lo alto del podio luso con la asombrosa marca de 9 dianas convertidas.', true, false),
('¿Qué selección ganó la final del Mundial 1930?', 'Uruguay', 'Argentina', 'Estados Unidos', 'Yugoslavia', 'a', 1, 'Campeones', 'La escuadra charrúa se coronó campeona del certamen de 1930 tras imponerse 4-2 en un vibrante y áspero partido ante la selección de Argentina en Montevideo.', true, false)
